'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { v4 as uuidv4 } from 'uuid';
import {
  Check, ChevronLeft, ChevronRight, Plus, Trash2,
  Users, BookOpen, Calendar, Building2,
} from 'lucide-react';
import { getAllOrganizations, saveOrganization, saveSession } from '@/lib/db';
import type { Member, MemberRole, Organization, Session, Agenda } from '@/types';

// ─── Constants ───────────────────────────────────────────────────────────────

const STEP_LABELS = ['基本情報', 'メンバー', '議題', '確認'];
const MAX_MEMBERS = 40;
const AVATAR_COLORS = [
  '#6366f1', '#8b5cf6', '#a855f7', '#ec4899', '#f43f5e',
  '#f97316', '#eab308', '#22c55e', '#14b8a6', '#06b6d4', '#3b82f6',
];

// ─── Shared UI pieces ────────────────────────────────────────────────────────

function InputField({
  label, required, error, children,
}: {
  label: string;
  required?: boolean;
  error?: string;
  children: React.ReactNode;
}) {
  return (
    <div className="space-y-1.5">
      <label className="block text-sm font-medium text-zinc-300">
        {label}
        {required && <span className="ml-1 text-red-400">*</span>}
      </label>
      {children}
      {error && <p className="text-xs text-red-400">{error}</p>}
    </div>
  );
}

function TextInput(props: React.InputHTMLAttributes<HTMLInputElement>) {
  return (
    <input
      {...props}
      className={`w-full rounded-lg border border-zinc-700 bg-zinc-800 px-3 py-2 text-sm text-white placeholder-zinc-600 outline-none transition-colors focus:border-zinc-500 focus:ring-1 focus:ring-zinc-500 ${props.className ?? ''}`}
    />
  );
}

function Avatar({ member, size = 'md' }: { member: Member; size?: 'sm' | 'md' }) {
  const dim = size === 'sm' ? 'h-6 w-6 text-[10px]' : 'h-8 w-8 text-xs';
  return (
    <span
      className={`flex shrink-0 items-center justify-center rounded-full font-bold text-white ${dim}`}
      style={{ backgroundColor: member.avatarColor }}
    >
      {member.lastName.charAt(0)}
    </span>
  );
}

function RoleButton({
  active, onClick, children,
}: {
  active: boolean;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${
        active
          ? 'bg-white text-black'
          : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700 hover:text-zinc-200'
      }`}
    >
      {children}
    </button>
  );
}

function SummarySection({
  icon, title, children,
}: {
  icon: React.ReactNode;
  title: string;
  children: React.ReactNode;
}) {
  return (
    <div className="rounded-xl border border-zinc-800 bg-zinc-900 p-4 space-y-3">
      <div className="flex items-center gap-2 text-zinc-400">
        {icon}
        <span className="text-xs font-semibold uppercase tracking-wider">{title}</span>
      </div>
      <div>{children}</div>
    </div>
  );
}

function SummaryRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex gap-3 text-sm">
      <span className="w-20 shrink-0 text-zinc-500">{label}</span>
      <span className="text-zinc-200">{value}</span>
    </div>
  );
}

// ─── Step indicator ───────────────────────────────────────────────────────────

function StepIndicator({ current }: { current: number }) {
  return (
    <div className="mb-8 flex items-start justify-center">
      {STEP_LABELS.map((label, i) => {
        const step = i + 1;
        const isDone = step < current;
        const isActive = step === current;
        return (
          <div key={step} className="flex items-start">
            <div className="flex flex-col items-center gap-1.5">
              <div
                className={`flex h-8 w-8 items-center justify-center rounded-full text-sm font-semibold transition-all ${
                  isDone
                    ? 'bg-white text-black'
                    : isActive
                    ? 'bg-white text-black ring-4 ring-white/20'
                    : 'bg-zinc-800 text-zinc-500'
                }`}
              >
                {isDone ? <Check className="h-4 w-4" /> : step}
              </div>
              <span className={`text-xs whitespace-nowrap ${isActive ? 'text-white' : 'text-zinc-600'}`}>
                {label}
              </span>
            </div>
            {i < STEP_LABELS.length - 1 && (
              <div className={`mt-4 mx-2 h-px w-10 sm:w-16 shrink-0 ${isDone ? 'bg-white' : 'bg-zinc-800'}`} />
            )}
          </div>
        );
      })}
    </div>
  );
}

// ─── Main page ────────────────────────────────────────────────────────────────

interface Step1Errors {
  orgName?: string;
  sessionTitle?: string;
}

export default function SetupPage() {
  const router = useRouter();
  const [step, setStep] = useState(1);
  const [saving, setSaving] = useState(false);

  // Step 1
  const [orgName, setOrgName] = useState('');
  const [groupName, setGroupName] = useState('');
  const [sessionTitle, setSessionTitle] = useState('');
  const [datetime, setDatetime] = useState('');
  const [location, setLocation] = useState('');
  const [step1Errors, setStep1Errors] = useState<Step1Errors>({});

  // Step 2
  const [members, setMembers] = useState<Member[]>([]);
  const [lastName, setLastName] = useState('');
  const [firstName, setFirstName] = useState('');
  const [email, setEmail] = useState('');
  const [memberError, setMemberError] = useState('');

  // Step 3
  const [agendas, setAgendas] = useState<{ id: string; title: string }[]>([]);
  const [agendaInput, setAgendaInput] = useState('');

  // Pre-fill organization from DB
  useEffect(() => {
    getAllOrganizations().then((orgs) => {
      if (orgs.length > 0) {
        setOrgName(orgs[0].name);
        setGroupName(orgs[0].groupName ?? '');
      }
    });
  }, []);

  // ── Step 1 ────────────────────────────────────────────────────────────────

  function validateStep1(): boolean {
    const errs: Step1Errors = {};
    if (!orgName.trim()) errs.orgName = '組織名は必須です';
    if (!sessionTitle.trim()) errs.sessionTitle = '会議名は必須です';
    setStep1Errors(errs);
    return Object.keys(errs).length === 0;
  }

  // ── Step 2 ────────────────────────────────────────────────────────────────

  function addMember() {
    if (!lastName.trim()) {
      setMemberError('姓は必須です');
      return;
    }
    if (members.length >= MAX_MEMBERS) {
      setMemberError(`メンバーは最大 ${MAX_MEMBERS} 名です`);
      return;
    }
    const newMember: Member = {
      id: uuidv4(),
      lastName: lastName.trim(),
      firstName: firstName.trim(),
      email: email.trim(),
      role: 'member',
      avatarColor: AVATAR_COLORS[members.length % AVATAR_COLORS.length],
    };
    setMembers((prev) => [...prev, newMember]);
    setLastName('');
    setFirstName('');
    setEmail('');
    setMemberError('');
  }

  function removeMember(id: string) {
    setMembers((prev) => prev.filter((m) => m.id !== id));
  }

  function setMemberRole(id: string, role: MemberRole) {
    setMembers((prev) => {
      // For exclusive roles (chair/vice): strip that role from current holder
      const stripped = prev.map((m) => {
        if (m.id === id) return m;
        if ((role === 'chair' || role === 'vice') && m.role === role) {
          return { ...m, role: 'member' as MemberRole };
        }
        return m;
      });
      // Toggle target member: if already has this role → revert to 'member'
      return stripped.map((m) => {
        if (m.id !== id) return m;
        return { ...m, role: m.role === role ? 'member' : role };
      });
    });
  }

  // ── Step 3 ────────────────────────────────────────────────────────────────

  function addAgenda() {
    const title = agendaInput.trim();
    if (!title) return;
    setAgendas((prev) => [...prev, { id: uuidv4(), title }]);
    setAgendaInput('');
  }

  function removeAgenda(id: string) {
    setAgendas((prev) => prev.filter((a) => a.id !== id));
  }

  // ── Step 4: Save ──────────────────────────────────────────────────────────

  async function handleStart() {
    setSaving(true);
    try {
      const now = new Date().toISOString();
      const orgId = uuidv4();
      const sessionId = uuidv4();

      const org: Organization = {
        id: orgId,
        name: orgName.trim(),
        groupName: groupName.trim(),
      };

      const sessionAgendas: Agenda[] = agendas.map((a, i) => ({
        id: a.id,
        sessionId,
        order: i + 1,
        title: a.title,
        talks: [],
      }));

      const session: Session = {
        id: sessionId,
        organizationId: orgId,
        title: sessionTitle.trim(),
        datetime,
        location: location.trim(),
        members,
        agendas: sessionAgendas,
        status: 'active',
        createdAt: now,
        updatedAt: now,
      };

      await saveOrganization(org);
      await saveSession(session);
      router.push(`/record/${sessionId}`);
    } finally {
      setSaving(false);
    }
  }

  // ── Navigation ────────────────────────────────────────────────────────────

  function goNext() {
    if (step === 1 && !validateStep1()) return;
    setStep((s) => Math.min(s + 1, 4));
  }

  function goBack() {
    setStep((s) => Math.max(s - 1, 1));
  }

  // ── Render ────────────────────────────────────────────────────────────────

  return (
    <div className="min-h-screen bg-[#0f0f0f] text-white">
      <div className="mx-auto max-w-2xl px-4 py-10 sm:px-6">

        {/* Page header */}
        <div className="mb-8 text-center">
          <h1 className="text-2xl font-bold tracking-tight">新しい会議セッション</h1>
          <p className="mt-1 text-sm text-zinc-500">ステップ {step} / {STEP_LABELS.length}</p>
        </div>

        <StepIndicator current={step} />

        {/* Card */}
        <div className="rounded-2xl border border-zinc-800 bg-zinc-900/40 p-6">

          {/* ── Step 1: Basic info ─────────────────────────────────────────── */}
          {step === 1 && (
            <div className="space-y-5">
              <h2 className="text-lg font-semibold">基本情報</h2>

              <InputField label="組織名" required error={step1Errors.orgName}>
                <TextInput
                  value={orgName}
                  onChange={(e) => {
                    setOrgName(e.target.value);
                    setStep1Errors((p) => ({ ...p, orgName: undefined }));
                  }}
                  placeholder="例：○○委員会"
                />
              </InputField>

              <InputField label="部会名">
                <TextInput
                  value={groupName}
                  onChange={(e) => setGroupName(e.target.value)}
                  placeholder="例：第1部会（任意）"
                />
              </InputField>

              <InputField label="会議名" required error={step1Errors.sessionTitle}>
                <TextInput
                  value={sessionTitle}
                  onChange={(e) => {
                    setSessionTitle(e.target.value);
                    setStep1Errors((p) => ({ ...p, sessionTitle: undefined }));
                  }}
                  placeholder="例：第12回定例会"
                />
              </InputField>

              <InputField label="日時">
                <TextInput
                  type="datetime-local"
                  value={datetime}
                  onChange={(e) => setDatetime(e.target.value)}
                />
              </InputField>

              <InputField label="場所">
                <TextInput
                  value={location}
                  onChange={(e) => setLocation(e.target.value)}
                  placeholder="例：第1会議室"
                />
              </InputField>
            </div>
          )}

          {/* ── Step 2: Members ────────────────────────────────────────────── */}
          {step === 2 && (
            <div className="space-y-5">
              <div className="flex items-center justify-between">
                <h2 className="text-lg font-semibold">メンバー登録</h2>
                <span className={`text-sm tabular-nums ${members.length >= MAX_MEMBERS ? 'text-red-400' : 'text-zinc-500'}`}>
                  {members.length} / {MAX_MEMBERS} 名
                </span>
              </div>

              {/* Add form */}
              <div className="rounded-xl border border-zinc-700 bg-zinc-800/50 p-4 space-y-3">
                <div className="grid grid-cols-2 gap-3">
                  <InputField label="姓" required>
                    <TextInput
                      value={lastName}
                      onChange={(e) => { setLastName(e.target.value); setMemberError(''); }}
                      placeholder="山田"
                      onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); addMember(); } }}
                    />
                  </InputField>
                  <InputField label="名">
                    <TextInput
                      value={firstName}
                      onChange={(e) => setFirstName(e.target.value)}
                      placeholder="太郎"
                      onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); addMember(); } }}
                    />
                  </InputField>
                </div>
                <InputField label="メールアドレス">
                  <TextInput
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="taro@example.com"
                    onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); addMember(); } }}
                  />
                </InputField>
                {memberError && <p className="text-xs text-red-400">{memberError}</p>}
                <button
                  type="button"
                  onClick={addMember}
                  disabled={members.length >= MAX_MEMBERS}
                  className="flex w-full items-center justify-center gap-2 rounded-lg border border-zinc-600 bg-zinc-700 py-2 text-sm font-medium text-white transition-colors hover:bg-zinc-600 disabled:cursor-not-allowed disabled:opacity-40"
                >
                  <Plus className="h-4 w-4" />
                  メンバーを追加
                </button>
              </div>

              {/* Member list */}
              {members.length > 0 ? (
                <ul className="space-y-2">
                  {members.map((m) => (
                    <li
                      key={m.id}
                      className="flex items-center gap-3 rounded-xl border border-zinc-800 bg-zinc-900 p-3"
                    >
                      <Avatar member={m} />
                      <div className="min-w-0 flex-1">
                        <p className="truncate text-sm font-medium text-white">
                          {m.lastName}{m.firstName ? ` ${m.firstName}` : ''}
                        </p>
                        {m.email && (
                          <p className="truncate text-xs text-zinc-500">{m.email}</p>
                        )}
                      </div>
                      <div className="flex shrink-0 items-center gap-1.5">
                        <RoleButton active={m.role === 'chair'} onClick={() => setMemberRole(m.id, 'chair')}>
                          議長
                        </RoleButton>
                        <RoleButton active={m.role === 'vice'} onClick={() => setMemberRole(m.id, 'vice')}>
                          副議長
                        </RoleButton>
                        <RoleButton active={m.role === 'exec'} onClick={() => setMemberRole(m.id, 'exec')}>
                          役員
                        </RoleButton>
                        <button
                          type="button"
                          onClick={() => removeMember(m.id)}
                          className="ml-1 flex h-6 w-6 items-center justify-center rounded text-zinc-600 transition-colors hover:bg-zinc-800 hover:text-red-400"
                        >
                          <Trash2 className="h-3.5 w-3.5" />
                        </button>
                      </div>
                    </li>
                  ))}
                </ul>
              ) : (
                <div className="rounded-xl border border-dashed border-zinc-800 py-10 text-center">
                  <Users className="mx-auto mb-2 h-6 w-6 text-zinc-700" />
                  <p className="text-sm text-zinc-600">メンバーを追加してください</p>
                </div>
              )}
            </div>
          )}

          {/* ── Step 3: Agendas ────────────────────────────────────────────── */}
          {step === 3 && (
            <div className="space-y-5">
              <h2 className="text-lg font-semibold">議題リスト</h2>

              <div className="flex gap-2">
                <input
                  type="text"
                  value={agendaInput}
                  onChange={(e) => setAgendaInput(e.target.value)}
                  onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); addAgenda(); } }}
                  placeholder="議題を入力（Enter で追加）"
                  className="flex-1 rounded-lg border border-zinc-700 bg-zinc-800 px-3 py-2 text-sm text-white placeholder-zinc-600 outline-none transition-colors focus:border-zinc-500 focus:ring-1 focus:ring-zinc-500"
                />
                <button
                  type="button"
                  onClick={addAgenda}
                  className="flex shrink-0 items-center gap-1.5 rounded-lg border border-zinc-600 bg-zinc-700 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-zinc-600"
                >
                  <Plus className="h-4 w-4" />
                  追加
                </button>
              </div>

              {agendas.length > 0 ? (
                <ol className="space-y-2">
                  {agendas.map((a, i) => (
                    <li
                      key={a.id}
                      className="flex items-center gap-3 rounded-xl border border-zinc-800 bg-zinc-900 px-4 py-3"
                    >
                      <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-zinc-800 text-xs font-semibold text-zinc-400">
                        {i + 1}
                      </span>
                      <span className="flex-1 text-sm text-white">{a.title}</span>
                      <button
                        type="button"
                        onClick={() => removeAgenda(a.id)}
                        className="text-zinc-600 transition-colors hover:text-red-400"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </li>
                  ))}
                </ol>
              ) : (
                <div className="rounded-xl border border-dashed border-zinc-800 py-10 text-center">
                  <BookOpen className="mx-auto mb-2 h-6 w-6 text-zinc-700" />
                  <p className="text-sm text-zinc-600">議題を追加してください</p>
                </div>
              )}
            </div>
          )}

          {/* ── Step 4: Confirm ────────────────────────────────────────────── */}
          {step === 4 && (
            <div className="space-y-4">
              <h2 className="text-lg font-semibold">内容確認</h2>

              <SummarySection icon={<Building2 className="h-4 w-4" />} title="組織情報">
                <div className="space-y-2">
                  <SummaryRow label="組織名" value={orgName} />
                  {groupName && <SummaryRow label="部会名" value={groupName} />}
                </div>
              </SummarySection>

              <SummarySection icon={<Calendar className="h-4 w-4" />} title="会議情報">
                <div className="space-y-2">
                  <SummaryRow label="会議名" value={sessionTitle} />
                  {datetime && (
                    <SummaryRow
                      label="日時"
                      value={new Intl.DateTimeFormat('ja-JP', {
                        year: 'numeric', month: 'long', day: 'numeric',
                        hour: '2-digit', minute: '2-digit',
                      }).format(new Date(datetime))}
                    />
                  )}
                  {location && <SummaryRow label="場所" value={location} />}
                </div>
              </SummarySection>

              <SummarySection icon={<Users className="h-4 w-4" />} title={`メンバー（${members.length} 名）`}>
                {members.length === 0 ? (
                  <p className="text-sm text-zinc-500">未登録</p>
                ) : (
                  <ul className="space-y-2">
                    {members.map((m) => (
                      <li key={m.id} className="flex items-center gap-2">
                        <Avatar member={m} size="sm" />
                        <span className="text-sm text-zinc-300">
                          {m.lastName}{m.firstName ? ` ${m.firstName}` : ''}
                        </span>
                        {m.role !== 'member' && (
                          <span className="rounded bg-zinc-800 px-1.5 py-0.5 text-xs text-zinc-400">
                            {m.role === 'chair' ? '議長' : m.role === 'vice' ? '副議長' : '役員'}
                          </span>
                        )}
                      </li>
                    ))}
                  </ul>
                )}
              </SummarySection>

              <SummarySection icon={<BookOpen className="h-4 w-4" />} title={`議題（${agendas.length} 件）`}>
                {agendas.length === 0 ? (
                  <p className="text-sm text-zinc-500">未登録</p>
                ) : (
                  <ol className="space-y-1.5">
                    {agendas.map((a, i) => (
                      <li key={a.id} className="flex gap-2 text-sm text-zinc-300">
                        <span className="shrink-0 text-zinc-600">{i + 1}.</span>
                        {a.title}
                      </li>
                    ))}
                  </ol>
                )}
              </SummarySection>
            </div>
          )}
        </div>

        {/* Navigation */}
        <div className="mt-6 flex items-center justify-between">
          {step > 1 ? (
            <button
              type="button"
              onClick={goBack}
              className="flex items-center gap-1.5 rounded-lg border border-zinc-700 px-4 py-2.5 text-sm font-medium text-zinc-300 transition-colors hover:border-zinc-600 hover:text-white"
            >
              <ChevronLeft className="h-4 w-4" />
              戻る
            </button>
          ) : (
            <button
              type="button"
              onClick={() => router.push('/')}
              className="flex items-center gap-1.5 rounded-lg border border-zinc-700 px-4 py-2.5 text-sm font-medium text-zinc-300 transition-colors hover:border-zinc-600 hover:text-white"
            >
              <ChevronLeft className="h-4 w-4" />
              キャンセル
            </button>
          )}

          {step < 4 ? (
            <button
              type="button"
              onClick={goNext}
              className="flex items-center gap-1.5 rounded-lg bg-white px-5 py-2.5 text-sm font-semibold text-black transition-colors hover:bg-zinc-200"
            >
              次へ
              <ChevronRight className="h-4 w-4" />
            </button>
          ) : (
            <button
              type="button"
              onClick={handleStart}
              disabled={saving}
              className="flex items-center gap-2 rounded-lg bg-white px-5 py-2.5 text-sm font-semibold text-black transition-all hover:bg-zinc-200 disabled:opacity-60"
            >
              {saving ? (
                <>
                  <span className="h-4 w-4 animate-spin rounded-full border-2 border-black/30 border-t-black" />
                  保存中…
                </>
              ) : (
                '会議を開始する'
              )}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
